const canvas=document.getElementById("particles-canvas"),ctx=canvas.getContext("2d"),heroEl=document.getElementById("hero");let W,H;const mouse={x:-9999,y:-9999};function resize(){heroEl.getBoundingClientRect(),W=canvas.width=heroEl.offsetWidth,H=canvas.height=heroEl.offsetHeight}resize(),window.addEventListener("resize",resize),heroEl.addEventListener("mousemove",t=>{let e=heroEl.getBoundingClientRect();mouse.x=t.clientX-e.left,mouse.y=t.clientY-e.top}),heroEl.addEventListener("mouseleave",()=>{mouse.x=-9999,mouse.y=-9999});const PARTICLE_COUNT=90,CONNECTION_DIST=160,MOUSE_DIST=200,GREEN={r:0,g:255,b:136},CYAN={r:0,g:229,b:204};function colorStr(t,e){return`rgba(${t.r},${t.g},${t.b},${e})`}class Particle{constructor(){this.reset()}reset(){this.x=Math.random()*W,this.y=Math.random()*H,this.vx=(Math.random()-.5)*.35,this.vy=(Math.random()-.5)*.35,this.r=1.8*Math.random()+.6,this.color=Math.random()>.5?GREEN:CYAN,this.alpha=.5*Math.random()+.3}update(){let t=mouse.x-this.x,e=mouse.y-this.y,o=Math.sqrt(t*t+e*e);if(o<200){let r=(200-o)/200*.012;this.vx+=t*r*.1,this.vy+=e*r*.1}this.vx*=.98,this.vy*=.98,this.x+=this.vx,this.y+=this.vy,this.x<-20&&(this.x=W+20),this.x>W+20&&(this.x=-20),this.y<-20&&(this.y=H+20),this.y>H+20&&(this.y=-20)}draw(){ctx.beginPath(),ctx.arc(this.x,this.y,this.r,0,2*Math.PI),ctx.fillStyle=colorStr(this.color,this.alpha),ctx.shadowBlur=8,ctx.shadowColor=colorStr(this.color,.5),ctx.fill(),ctx.shadowBlur=0}}const particles=Array.from({length:90},()=>new Particle);function drawConnections(){for(let t=0;t<particles.length;t++)for(let e=t+1;e<particles.length;e++){let o=particles[t],r=particles[e],s=o.x-r.x,i=o.y-r.y,l=Math.sqrt(s*s+i*i);if(l<160){let a=(1-l/160)*.25,n=ctx.createLinearGradient(o.x,o.y,r.x,r.y);n.addColorStop(0,colorStr(o.color,a)),n.addColorStop(1,colorStr(r.color,a)),ctx.beginPath(),ctx.moveTo(o.x,o.y),ctx.lineTo(r.x,r.y),ctx.strokeStyle=n,ctx.lineWidth=.7,ctx.stroke()}}}function animate(){ctx.clearRect(0,0,W,H),drawConnections(),particles.forEach(t=>{t.update(),t.draw()}),requestAnimationFrame(animate)}animate(),document.addEventListener("DOMContentLoaded",()=>{setTimeout(()=>{document.querySelectorAll(".outline-text").forEach(t=>t.classList.add("revealed"))},300)});